const input = $input.first().json;
const body = input.body || input;

const business_id = body.business_id || '';
const onboarding_answers = body.onboarding_answers || null;
const force_rebuild = body.force_rebuild === true;
const is_scheduled = !business_id;

return [{ json: { business_id, onboarding_answers, force_rebuild, is_scheduled } }];

const businesses = $input.first().json;
const arr = Array.isArray(businesses) ? businesses : [businesses];
return arr.map(b => ({ json: { business_id: b.id, onboarding_answers: null, force_rebuild: false, is_scheduled: true } }));

const bizArr = $('Fetch Business Data').first().json;
const onbArr = $('Fetch Onboarding Answers').first().json;
const loopData = $('Loop Each Business').first().json;

const biz = Array.isArray(bizArr) ? bizArr[0] : bizArr || {};
const onb = Array.isArray(onbArr) ? onbArr[0] : onbArr || {};
const answers = loopData.onboarding_answers || onb || {};

return [{ json: {
  business_id: loopData.business_id,
  business_name: biz.business_name || '',
  industry: biz.industry || '',
  target_audience: biz.target_audience || answers.target_audience || '',
  brand_tone: biz.brand_tone || answers.brand_tone || '',
  marketing_goal: biz.marketing_goal || answers.marketing_goal || '',
  location: biz.location || answers.city || '',
  competitors: biz.competitors || answers.competitors || '',
  usp: answers.usp || biz.usp || '',
  products: answers.products_services || '',
  pain_points: answers.customer_pain_points || '',
  brand_values: answers.brand_values || '',
  content_style: answers.content_style_preference || '',
  budget_range: answers.marketing_budget || '',
  primary_language: biz.primary_language || answers.primary_language || 'English'
} }];

const bizData = $('Merge Business Data').first().json;
const compRaw = $('SerpAPI Direct Competitors').first().json || {};
const leadersRaw = $('SerpAPI Industry Leaders').first().json || {};
const trendsRaw = $('SerpAPI Trending Content').first().json || {};

const competitors = (compRaw.organic_results || []).slice(0, 5).map(r => ({
  name: r.title || '',
  url: r.link || '',
  snippet: r.snippet || ''
}));

const leaders = (leadersRaw.organic_results || []).slice(0, 5).map(r => ({
  name: r.title || '',
  snippet: r.snippet || ''
}));

const trends = (trendsRaw.organic_results || []).slice(0, 5).map(r => r.snippet || r.title || '').filter(Boolean);

const competitorNames = competitors.map(c => c.name).filter(Boolean).slice(0, 3);

return [{ json: {
  ...bizData,
  competitors_found: competitors,
  industry_leaders: leaders,
  trending_content: trends,
  competitor_names: competitorNames
} }];

const ctx = $input.first().json;
const names = ctx.competitor_names || [];
const items = names.map(name => ({ json: { ...ctx, current_competitor: name } }));
if (items.length === 0) items.push({ json: { ...ctx, current_competitor: '' } });
return items;

const ctx = $('Split Competitors').first().json;
const imgRaw = $input.first().json || {};

const images = (imgRaw.images_results || []).slice(0, 5).map(r => ({
  title: r.title || '',
  source: r.source || '',
  thumbnail: r.thumbnail || ''
}));

const compAnalysis = {
  competitor: ctx.current_competitor,
  visual_themes: images.map(i => i.title).filter(Boolean).slice(0, 3),
  sources: images.map(i => i.source).filter(Boolean).slice(0, 3)
};

return [{ json: { ...ctx, competitor_analysis: compAnalysis } }];

