const raw = $input.first().json.content?.[0]?.text || '';
let c = {};
try { c = JSON.parse(raw); }
catch(e) { const m = raw.match(/{[\s\S]*}/); if(m) try { c = JSON.parse(m[0]); } catch(e2) {} }

const ctx = $('Parse Audience Intel').first().json;

return [{ json: {
  business_id: ctx.business_id,
  business_name: ctx.business_name,
  brand_dna: c,
  audience_intelligence: ctx.audience_intelligence || {},
  competitor_analysis: ctx.competitor_analysis || {},
  generated_at: new Date().toISOString()
} }];

// Fetch existing versions to keep last 3
const ctx = $input.first().json;

// Build the upsert row
const row = {
  business_id: ctx.business_id,
  brand_dna: JSON.stringify(ctx.brand_dna),
  audience_intelligence: JSON.stringify(ctx.audience_intelligence),
  competitor_analysis: JSON.stringify(ctx.competitor_analysis),
  version: new Date().toISOString().slice(0, 10).replace(/-/g, ''),
  generated_at: ctx.generated_at,
  status: 'active'
};

return [{ json: { ...ctx, upsert_row: row } }];

const oldVersions = $('Fetch Old Versions').first().json;
const arr = Array.isArray(oldVersions) ? oldVersions : [];
const ctx = $('Prepare Save').first().json;

// Mark old versions (beyond 3) for deletion
const idsToDelete = arr.map(v => v.id).filter(Boolean);

return [{ json: { ...ctx, old_version_ids: idsToDelete } }];

